import Vue from 'vue'
import VueRouter from 'vue-router'
import getRoutes from './get_routes.js'

Vue.use(VueRouter);

const routes = [
	{
		path: '/test/d3',
		component: () => import('../test/d3/d3.vue'),
		children: getRoutes([
			{
				component: (path)=> ()=> import(`../test/d3/${path}.vue`) ,
				paths: ['zoomable-circle-packing', 'zoomable-circle-packing.copy', 'mobile-patent-suits', 'mobile-patent-suits.copy', 'nested-treemap', 'quadtree-demo1', 'quadtree-demo2', 'cluster_dendrogram', 'indented_tree']
			}
		])
	},
	{
		path: '/test/utils',
		component: () => import('../test/utils/utils.vue'),
		children: getRoutes([
			{
				component: (path)=> ()=> import(`../test/utils/${path}.vue`),
				paths: ['timer', 'color']
			}
		])
	},
	{
		path: '/code_analysis',
		component: () => import('../views/code_analysis/code_analysis.vue'),
	},
	{
		path: '/show_myself',
		component: () => import('../views/show_myself/show_myself.vue'),
	},
	{
		path: '/draw',
		component: () => import('../tools/draw/example.vue'),
	},
	{
		path: '/mathjax',
		component: () => import('../tools/mathjax/tex_to_image.vue'),
	},
	{
		path: '/components',
		component: () => import('../components/components.vue'),
		children: getRoutes([
			{
				component: (path)=> ()=> import(`../components/${path}/example.vue`),
				paths: ['scrollbar', 'context_menu', 'tree', 'message', 'side']
			},
			{
				component: (path)=> ()=> import(`../components/${path}/index.vue`),
				paths: ['element-ui.copy/color-picker', 'element-ui.copy/tree']
			}
		])
	},
]

const router = new VueRouter({
	mode: 'hash',
	base: process.env.BASE_URL,
	routes
})

